SELECT id, name, description, database_id
FROM db_table
WHERE database_id = #{databaseId} AND name = #{name}

SELECT id, name, description, database_id
FROM db_table
WHERE database_id = #{databaseId}

SELECT t.id AS id, t.name AS name, t.description AS description, t.database_id AS database_id, c.id AS c_id, c.name AS c_name, c.type AS c_type, c.description AS c_description, c.is_primary_key AS c_is_primary_key, c.table_id AS c_table_id FROM db_table t LEFT JOIN db_column c ON c.table_id = t.id WHERE t.id IN
#{id}
ORDER BY t.name, c.name

SELECT t.id AS id, t.name AS name, t.description AS description, t.database_id AS database_id, c.id AS c_id, c.name AS c_name, c.type AS c_type, c.description AS c_description, c.is_primary_key AS c_is_primary_key, c.table_id AS c_table_id FROM db_table t LEFT JOIN db_column c ON c.table_id = t.id WHERE t.database_id = #{databaseId} AND t.name IN
#{name}
ORDER BY t.name, c.name

SELECT id, name, description, database_id
FROM db_table
WHERE id = #{id}
